var maxZoneImbalance = function(loads, edges) {
    var n = loads.length;
    // 无边则无有效供电区
    if (edges.length === 0) return -1;

    // 并查集初始化
    var parent = [];
    for (var i = 0; i < n; i++) parent[i] = i;

    function find(x) {
        while (parent[x] !== x) {
            parent[x] = parent[parent[x]];
            x = parent[x];
        }
        return x;
    }

    function union(a, b) {
        a = find(a);
        b = find(b);
        if (a !== b) parent[b] = a;
    }

    // 按边合并同一供电区
    for (var i = 0; i < edges.length; i++) {
        union(edges[i][0], edges[i][1]);
    }

    // 按根分组
    var groups = {};
    for (var i = 0; i < n; i++) {
        var r = find(i);
        if (!groups[r]) groups[r] = [];
        groups[r].push(i);
    }

    var ans = -1;
    for (var key in groups) {
        var nodes = groups[key];
        if (nodes.length < 2) continue; // 孤立节点不算
        var mn = loads[nodes[0]], mx = loads[nodes[0]];
        for (var j = 0; j < nodes.length; j++) {
            var val = loads[nodes[j]];
            if (val < mn) mn = val;
            if (val > mx) mx = val;
        }
        // 不均衡度 = 负载差 × 节点数
        var imbalance = (mx - mn) * nodes.length;
        if (imbalance > ans) ans = imbalance;
    }
    return ans;
};
